lemma bounded_comp_bounded {f : ℝ → ℝ} {X : Ω → ℝ} {C : ℝ}
    (hbdd : ∀ x : ℝ, ‖f x‖ ≤ C) :
    ∀ ω : Ω, ‖f (X ω)‖ ≤ C

lemma exists_finset_isENet_of_totallyBounded {eps : ℝ} {s : Set A}
    (heps : 0 < eps) (hs : TotallyBounded s) :
    ∃ t : Finset A, IsENet t eps s

theorem entropy_sq_normalized [IsProbabilityMeasure μ] {f : Ω → ℝ}
    (hf_norm : ∫ ω, (f ω)^2 ∂μ = 1) :
    entropy μ (f · ^2) = ∫ ω, (f ω)^2 * log ((f ω)^2) ∂μ
